#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M, Noe, Nof;
        scanf("%d %d %d", &M, &Noe, &Nof);
        int count = 0;
        for (int Ns = 1; Ns <= M; Ns++) {
            int K = (int)ceil((double)Ns / Noe);
            if ((int)ceil((double)Ns / K) == Nof) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

