import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int M = sc.nextInt();
            int Noe = sc.nextInt();
            int Nof = sc.nextInt();
            int count = 0;
            for (int Ns = 1; Ns <= M; Ns++) {
                int K = (int)Math.ceil((double)Ns / Noe);
                if ((int)Math.ceil((double)Ns / K) == Nof) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

