const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [M, Noe, Nof] = readline().split(' ').map(Number);
    let count = 0;
    for (let Ns = 1; Ns <= M; Ns++) {
        const K = Math.ceil(Ns / Noe);
        if (Math.ceil(Ns / K) === Nof) {
            count++;
        }
    }
    console.log(count);
